/**
 * components/Sidebar.jsx — Polished role-based navigation sidebar.
 */
import { NavLink } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const NAV_ITEMS = [
  { path: '/',          label: 'Dashboard',         icon: '📊', roles: ['super_admin','farm_manager','accountant','field_worker','vet','viewer'] },
  { path: '/milk',      label: 'Milk Entry',        icon: '🥛', roles: ['super_admin','farm_manager','field_worker'] },
  { path: '/cattle',    label: 'Cattle Health',     icon: '🐄', roles: ['super_admin','farm_manager','vet'] },
  { path: '/inventory', label: 'Inventory',         icon: '📦', roles: ['super_admin','farm_manager'] },
  { path: '/sales',     label: 'Sales',             icon: '💰', roles: ['super_admin','accountant','farm_manager'] },
  { path: '/employees', label: 'Employee Roster',   icon: '👥', roles: ['super_admin','accountant'] },
  { path: '/reports',   label: 'Financial Reports', icon: '📈', roles: ['super_admin','accountant'] },
];

const ROLE_LABELS = {
  super_admin:   'Super Admin',
  farm_manager:  'Farm Manager',
  accountant:    'Accountant',
  field_worker:  'Field Worker',
  vet:           'Veterinarian',
  viewer:        'Viewer',
};

const ROLE_COLORS = {
  super_admin:  'bg-purple-500',
  farm_manager: 'bg-green-500',
  accountant:   'bg-blue-500',
  field_worker: 'bg-yellow-500',
  vet:          'bg-red-400',
  viewer:       'bg-gray-400',
};

function Initials({ name }) {
  if (!name) return <span className="text-sm font-bold">?</span>;
  const parts = name.trim().split(' ');
  const init  = parts.length >= 2
    ? parts[0][0] + parts[parts.length - 1][0]
    : parts[0].slice(0, 2);
  return <span className="text-sm font-bold uppercase">{init}</span>;
}

export default function Sidebar() {
  const { user, logout } = useAuth();
  const visibleItems = NAV_ITEMS.filter(item => user && item.roles.includes(user.role));

  return (
    <aside className="flex flex-col h-screen w-64 fixed left-0 top-0 z-10 shadow-xl"
           style={{ background: 'linear-gradient(180deg, #14532d 0%, #166534 60%, #15803d 100%)' }}>

      {/* ── Brand ── */}
      <div className="px-5 py-5 border-b border-green-700 border-opacity-50">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 rounded-xl bg-white bg-opacity-15 flex items-center justify-center flex-shrink-0 shadow-inner border border-white border-opacity-10">
            <span className="text-xl">🥛</span>
          </div>
          <div>
            <div className="text-white font-bold text-sm leading-tight">Akshaya Farm Dairy</div>
            <div className="text-green-300 text-[10px] mt-0.5 font-light tracking-wide">Management System</div>
          </div>
        </div>
      </div>

      {/* ── Nav ── */}
      <nav className="flex-1 px-3 py-4 space-y-0.5 overflow-y-auto">
        <p className="text-green-400 text-[10px] font-semibold uppercase tracking-widest px-3 mb-2">Navigation</p>
        {visibleItems.map(item => (
          <NavLink
            key={item.path}
            to={item.path}
            end={item.path === '/'}
            className={({ isActive }) =>
              `flex items-center gap-3 px-3 py-2.5 rounded-xl text-sm font-medium transition-all duration-150
               ${isActive
                 ? 'bg-white bg-opacity-20 text-white shadow-sm'
                 : 'text-green-100 hover:bg-white hover:bg-opacity-10 hover:text-white'}`
            }
          >
            {({ isActive }) => (
              <>
                <span className={`w-8 h-8 rounded-lg flex items-center justify-center text-base flex-shrink-0 transition-colors
                  ${isActive ? 'bg-white bg-opacity-20' : 'bg-transparent'}`}>
                  {item.icon}
                </span>
                <span className="truncate">{item.label}</span>
                {isActive && <span className="ml-auto w-1.5 h-1.5 rounded-full bg-green-300 flex-shrink-0" />}
              </>
            )}
          </NavLink>
        ))}
      </nav>

      {/* ── User card ── */}
      <div className="px-3 pb-3">
        <div className="bg-white bg-opacity-10 rounded-xl border border-white border-opacity-10 p-3">
          <div className="flex items-center gap-3">
            {/* Avatar circle */}
            <div className={`w-9 h-9 rounded-xl flex items-center justify-center text-white flex-shrink-0 shadow
              ${ROLE_COLORS[user?.role] || 'bg-gray-500'}`}>
              <Initials name={user?.full_name} />
            </div>
            <div className="flex-1 min-w-0">
              <div className="text-white text-sm font-semibold truncate leading-tight">{user?.full_name || 'User'}</div>
              <div className="text-green-300 text-[10px] mt-0.5 truncate">{ROLE_LABELS[user?.role] || user?.role}</div>
            </div>
          </div>

          <button
            onClick={logout}
            className="mt-3 w-full flex items-center justify-center gap-2 px-3 py-2 rounded-lg text-xs
                       font-medium text-red-300 hover:bg-red-500 hover:text-white border border-red-400
                       border-opacity-30 hover:border-transparent transition-all duration-150">
            <span>🚪</span> Sign Out
          </button>
        </div>
      </div>
    </aside>
  );
}
